sp_angular_provider.script:
function scmTableColumnsCoordinatorService(
    scmTablePreferencesService,
    scmTableViewStateService,
    scmTableColumnSearchService,
) {
    "use strict";

    function buildColumnsState(options) {
        options = options || {};

        var columns = options.columns || [];
        var selectorState = scmTableViewStateService.syncColumnSelectorLists(
            columns,
            options.allColumnsAvailable || [],
        );

        var columnSearchTerms =
            scmTableColumnSearchService.syncColumnSearchTermsFromAppliedFilters(
                {
                    columns: columns,
                    appliedFilters: options.appliedFilters || [],
                },
            );

        var showTableHeader =
            scmTableViewStateService.shouldShowTableHeader(columns);

        return scmTableColumnSearchService
            .ensureChoiceValuesForColumnSearch({
                columns: columns,
                filterFieldMap: options.filterFieldMap || {},
                getChoiceOptionsForField: options.getChoiceOptionsForField,
                loadChoiceValues: options.loadChoiceValues,
            })
            .then(function () {
                return {
                    columns: columns,
                    selectedFieldsList: selectorState.selectedFieldsList,
                    unselectedFieldsList: selectorState.unselectedFieldsList,
                    fieldToAdd: selectorState.fieldToAdd,
                    fieldToRemove: selectorState.fieldToRemove,
                    columnSearchTerms: columnSearchTerms,
                    showTableHeader: showTableHeader,
                };
            });
    }

    function fetchColumnsState(options) {
        options = options || {};

        return scmTablePreferencesService
            .getTableColumns(options)
            .then(function (columns) {
                return buildColumnsState({
                    columns: columns,
                    allColumnsAvailable: options.allColumnsAvailable,
                    appliedFilters: options.appliedFilters,
                    filterFieldMap: options.filterFieldMap,
                    getChoiceOptionsForField: options.getChoiceOptionsForField,
                    loadChoiceValues: options.loadChoiceValues,
                });
            });
    }

    function ensureChoiceValuesForColumnSearch(options) {
        options = options || {};

        return scmTableColumnSearchService.ensureChoiceValuesForColumnSearch({
            columns: options.columns || [],
            filterFieldMap: options.filterFieldMap || {},
            getChoiceOptionsForField: options.getChoiceOptionsForField,
            loadChoiceValues: options.loadChoiceValues,
        });
    }

    return {
        buildColumnsState: buildColumnsState,
        fetchColumnsState: fetchColumnsState,
        ensureChoiceValuesForColumnSearch: ensureChoiceValuesForColumnSearch,
    };
}
